solution_code:
#include <iostream>
#include <iomanip>

template<typename T, typename U>
struct Pair
{
    T first{};
    U second{};
};

template<typename T, typename U>
void printPair(const Pair<T, U>& p)
{
    std::cout << '(' << p.first << ", " << p.second << ')' << '\n';
}

int main()
{
    int a{}, b{};
    std::cin >> a >> b;

    Pair<int, int> p1{ a, b };
    printPair(p1);

    double x{};
    int y{};
    std::cin >> x >> y;

    std::cout << std::fixed << std::setprecision(1);
    Pair<double, int> p2{ x, y };
    printPair(p2);

    return 0;
}

