solution_code:
#include <iostream>

template<typename T>
struct Bounds
{
    T low{};
    T high{};
};

template<typename T>
bool isInRange(const Bounds<T>& b, T value)
{
    return value >= b.low && value <= b.high;
}

int main()
{
    int iLow{}, iHigh{}, iVal{};
    std::cin >> iLow >> iHigh >> iVal;

    Bounds<int> intBounds{ iLow, iHigh };
    std::cout << (isInRange(intBounds, iVal) ? "in range" : "out of range") << '\n';

    double dLow{}, dHigh{}, dVal{};
    std::cin >> dLow >> dHigh >> dVal;

    Bounds<double> dblBounds{ dLow, dHigh };
    std::cout << (isInRange(dblBounds, dVal) ? "in range" : "out of range") << '\n';

    return 0;
}
